export const meta = {
  name: 'parallel_primality_check',
  description: 'Two parallel primality checks for 17 tolerating one failure, then synthesize surviving evidence',
  phases: [{ title: 'Parallel Checks' }, { title: 'Synthesis' }]
};

function textOf(r) {
  if (r == null) return '';
  if (typeof r === 'string') return r;
  if (r.content) return r.content;
  if (r.text) return r.text;
  if (r.output) return r.output;
  if (r.result) return r.result;
  return typeof r === 'object' ? JSON.stringify(r) : String(r);
}

phase('Parallel Checks');

const checks = await parallel([
  () => agent('Primality check #1 for the number 17: check divisors from 2 through floor(sqrt(17)). State clearly, in one concise sentence, whether 17 is prime (true/false) and why.'),
  () => agent('Primality check #2 for the number 17: apply the definition of a prime number to 17. State clearly, in one concise sentence, whether 17 is prime (true/false) and why.')
]);

let failedChecks = 0;
const evidence = [];
for (const r of checks) {
  const t = textOf(r).trim();
  if (t) evidence.push(t); else failedChecks += 1;
}

log('Surviving checks: ' + evidence.length + '; failed checks: ' + failedChecks);

let result;
if (evidence.length === 0) {
  // Both checkers failed: this is beyond the tolerated single failure.
  result = { prime: null, evidence: 'no surviving evidence — both checkers failed', failedChecks };
} else {
  phase('Synthesis');
  const block = evidence.map((e, i) => 'Checker ' + (i + 1) + ': ' + e).join('\n');
  const synth = await agent(
    'You are synthesizing primality evidence for the number 17.\n\n' +
    'Surviving evidence:\n' + block + '\n\n' +
    'Reply with ONLY a compact JSON object and nothing else (no prose, no markdown, no code fences):\n' +
    '{"prime": <true|false>, "evidence": "<one short sentence summarizing why>"}'
  );
  let parsed = {};
  try {
    const cleaned = textOf(synth).replace(/```/g, '').replace(/json/gi, '').trim();
    const m = cleaned.match(/\{[\s\S]*\}/);
    parsed = JSON.parse(m ? m[0] : cleaned);
  } catch (e) { parsed = {}; }
  result = {
    prime: parsed.prime,
    evidence: parsed.evidence,
    failedChecks
  };
}

result;

